/**
 * Minimal logger interface shared code can depend on. The server's
 * `createLogger(...)` and the PWA's client logger both satisfy this shape, so
 * either runtime can inject its own implementation into a repository factory.
 * When `log` is omitted, repositories use `NOOP_LOGGER` — silent, never throws.
 */
export type LogContext = Record<string, unknown>;

export interface RepoLogger {
    debug(message: string, context?: LogContext): void;
    info(message: string, context?: LogContext): void;
    warn(message: string, context?: LogContext): void;
    error(message: string, context?: LogContext): void;
}

export const NOOP_LOGGER: RepoLogger = {
    debug: () => { /* no-op */ },
    info: () => { /* no-op */ },
    warn: () => { /* no-op */ },
    error: () => { /* no-op */ },
};
